request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?created ?originalId ?normalizedId WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "38b17e822a5e4307ae051694293e4d0f" .
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName .
  OPTIONAL { ?model tai:modelCreated ?created . }
  OPTIONAL { ?model tai:originalId ?originalId . }
  OPTIONAL { ?model tai:normalizedId ?normalizedId . }
  FILTER(
    CONTAINS(LCASE(STR(?modelName)), "organ transportation") ||
    CONTAINS(LCASE(STR(?modelName)), "organ transport") ||
    CONTAINS(LCASE(STR(?modelName)), "transplant") ||
    CONTAINS(LCASE(STR(?modelName)), "organ")
  )
}
ORDER BY DESC(?created)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?created ?originalId ?normalizedId WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "38b17e822a5e4307ae051694293e4d0f" .
  ?model a bboExt:Model ;
         tai:belongsTo ?org .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  OPTIONAL { ?model tai:originalId ?originalId . }
  OPTIONAL { ?model tai:normalizedId ?normalizedId . }
  OPTIONAL { ?model tai:description ?modelDesc . }
  FILTER(
    CONTAINS(LCASE(STR(COALESCE(?modelName, ""))), "organ") ||
    CONTAINS(LCASE(STR(COALESCE(?modelName, ""))), "transport") ||
    CONTAINS(LCASE(STR(COALESCE(?modelDesc, ""))), "organ") ||
    CONTAINS(LCASE(STR(COALESCE(?modelDesc, ""))), "transport") ||
    CONTAINS(LCASE(STR(COALESCE(?modelName, ""))), "transplant") ||
    CONTAINS(LCASE(STR(COALESCE(?modelDesc, ""))), "transplant")
  )
}
ORDER BY DESC(?created)
LIMIT 25
